import{_ as l,r as t,o as r,c as i,b as a,d as n,e as c,f as e}from"./app-55c326ac.js";const d={},o=e(`<h1 id="交换机端口模式" tabindex="-1"><a class="header-anchor" href="#交换机端口模式" aria-hidden="true">#</a> 交换机端口模式</h1><h2 id="三种链路类型" tabindex="-1"><a class="header-anchor" href="#三种链路类型" aria-hidden="true">#</a> 三种链路类型</h2><ul><li>Access：只能属于1个VLAN，一般用于连接计算机端口</li><li>Trunk：允许多个VLAN，可以接受和发送多个VLAN报文，一般用于交换机与交换机相关的接口</li><li>Hybrid：可以允许多个VLAN，可以接受和发送多个VLAN报文，一般用于交换机的间接连接也可以用于连接用户计算机</li></ul><hr><h3 id="一-access接口" tabindex="-1"><a class="header-anchor" href="#一-access接口" aria-hidden="true">#</a> 一：Access接口</h3><p>一般用于连接终端用户，PC并不能识别带有tag的数据帧<br> 配置：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>interface G0/0/1    <span class="token comment">#切换到端口模式</span>
port link-type access   <span class="token comment">#设置端口类型</span>
port default vlan <span class="token number">2</span>     <span class="token comment">#设置所属VLAN</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="access端口的特点" tabindex="-1"><a class="header-anchor" href="#access端口的特点" aria-hidden="true">#</a> Access端口的特点</h4>`,8),u={href:"https://baike.baidu.com/item/PVID/10536481?fr=aladdin",target:"_blank",rel:"noopener noreferrer"},p=a("li",null,"当端口收到对端设备发送的帧是untagged。交换机将强制加上该端口的PVID",-1),h=a("li",null,"Access端口发往对端设备的以太网帧永远是untagges frame",-1),m=a("li",null,"一般的交换机默认端口类型是access。PVID默认是1，VLAN1由系统创建，不能被删除或者修改",-1),v=e(`<hr><h3 id="二-trunk接口" tabindex="-1"><a class="header-anchor" href="#二-trunk接口" aria-hidden="true">#</a> 二：Trunk接口</h3><p>access接口在发送数据帧时会丢弃tag，这样对方的设备就不知道数据帧属于哪个VLAN，当需要交换机携带标签来转发数据帧，携带tag发送数据帧。就会使用Trunk类型</p><p><strong><strong>Trunk不能实现不同VLAN间的通信，需要通过三层设备（路由/三层交换机）来实现</strong></strong></p><h4 id="设置端口为trunk类型" tabindex="-1"><a class="header-anchor" href="#设置端口为trunk类型" aria-hidden="true">#</a> 设置端口为Trunk类型</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>interface G0/0/0        <span class="token comment">#进去端口模式</span>
port link-type trunk    <span class="token comment">#设置端口为Trunk模式</span>
port trunk pvid vlan <span class="token number">3</span>  <span class="token comment">#设置端口的虚拟局域网ID(PVID)号，就是为untagged报文叫上默认的VLAN</span>
port trunk allow-pass vlan <span class="token number">5</span> <span class="token number">100</span>    <span class="token comment">#设置该端口允许哪些VLAN通过，华为交换机的Trunk接口默认只允许vlan1通过</span>
port trunk allow-pass vlan all  <span class="token comment">#允许所有vlan通过</span>
dis vlan    <span class="token comment">#查看所有vlan</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><p>Trunk接口的<strong><strong>特点</strong></strong>：</p></li><li><p>接收：看允不允许通过和有没有创建这个VLAN</p><ul><li>纯以太网帧：打上PVID tag然后转发</li><li>属于PVID的tag帧：保留tag直接转发</li><li>不属于PVID的tage帧：保留tag直接转发</li></ul></li><li><p>发送：看允不允许通过和有没有创建这个VLAN</p><ul><li>属于PVID的tag帧：去掉tag，变为纯以太网帧发送</li><li>不属于PVID的tag帧：保留tag直接发送</li></ul></li></ul>`,7);function k(g,_){const s=t("ExternalLinkIcon");return r(),i("div",null,[o,a("ol",null,[a("li",null,[n("仅仅允许VLAN ID与端口的"),a("a",u,[n("PVID"),c(s)]),n(" <端口的虚拟局域网ID号，关系到端口手法数据帧是的VLAN TAG标记>相同的数据帧通过本端口")]),p,h,m]),v])}const V=l(d,[["render",k],["__file","交换机端口模式.html.vue"]]);export{V as default};
